local ScreenGui = Instance.new("ScreenGui")local Main = Instance.new("Frame")local Title = Instance.new("TextLabel")local FlyBtn = Instance.new("TextButton")local SpeedInput = Instance.new("TextBox")local MinimizeBtn = Instance.new("TextButton")game:GetService("StarterGui"):SetCore("SendNotification", {    Title = "qkhanhdz Script";    Text = "v8: Fix triệt để lỗi NGƯỢC HƯỚNG Joystick";    Duration = 5;})ScreenGui.Parent = game:GetService("CoreGui")Main.Parent = ScreenGuiMain.Size = UDim2.new(0, 160, 0, 130)Main.Position = UDim2.new(0.5, -80, 0.5, -65)Main.BackgroundColor3 = Color3.fromRGB(15, 15, 15)Main.Active = trueMain.Draggable = trueMain.ClipsDescendants = trueTitle.Parent = MainTitle.Size = UDim2.new(1, -30, 0, 30)Title.Text = "qkhanhdz v8"Title.BackgroundColor3 = Color3.fromRGB(170, 0, 255)Title.TextColor3 = Color3.fromRGB(255, 255, 255)Title.Font = Enum.Font.SourceSansBoldMinimizeBtn.Parent = MainMinimizeBtn.Size = UDim2.new(0, 30, 0, 30)MinimizeBtn.Position = UDim2.new(1, -30, 0, 0)MinimizeBtn.Text = "-"MinimizeBtn.BackgroundColor3 = Color3.fromRGB(40, 40, 40)MinimizeBtn.TextColor3 = Color3.fromRGB(255, 255, 255)FlyBtn.Parent = MainFlyBtn.Size = UDim2.new(1, -10, 0, 40)FlyBtn.Position = UDim2.new(0, 5, 0, 40)FlyBtn.Text = "BẬT BAY"FlyBtn.BackgroundColor3 = Color3.fromRGB(60, 60, 60)FlyBtn.TextColor3 = Color3.fromRGB(255, 255, 255)SpeedInput.Parent = MainSpeedInput.Size = UDim2.new(1, -10, 0, 35)SpeedInput.Position = UDim2.new(0, 5, 0, 85)SpeedInput.Text = "50"SpeedInput.BackgroundColor3 = Color3.fromRGB(30, 30, 30)SpeedInput.TextColor3 = Color3.fromRGB(0, 255, 0)local flying = falselocal player = game.Players.LocalPlayerlocal camera = workspace.CurrentCameraMinimizeBtn.MouseButton1Click:Connect(function()    if Main.Size.Y.Offset > 35 then        Main:TweenSize(UDim2.new(0, 160, 0, 30), "Out", "Quad", 0.3, true)        MinimizeBtn.Text = "+"    else        Main:TweenSize(UDim2.new(0, 160, 0, 130), "Out", "Quad", 0.3, true)        MinimizeBtn.Text = "-"    endend)FlyBtn.MouseButton1Click:Connect(function()    flying = not flying    local char = player.Character    local root = char and char:FindFirstChild("HumanoidRootPart")    local hum = char and char:FindFirstChildOfClass("Humanoid")        if not root or not hum then return end    if flying then        FlyBtn.Text = "TẮT BAY"        FlyBtn.BackgroundColor3 = Color3.fromRGB(200, 0, 0)                local bv = Instance.new("BodyVelocity", root)        bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)        bv.Velocity = Vector3.zero                local bg = Instance.new("BodyGyro", root)        bg.MaxTorque = Vector3.new(math.huge, math.huge, math.huge)        bg.P = 90000                hum.PlatformStand = true                task.spawn(function()            while flying and root and bv.Parent do                local speed = tonumber(SpeedInput.Text) or 50                bg.CFrame = camera.CFrame                                local moveDir = hum.MoveDirection                if moveDir.Magnitude > 0 then                    -- Lấy hướng phẳng của Camera (bỏ qua trục Y)                    local flatLook = Vector3.new(camera.CFrame.LookVector.X, 0, camera.CFrame.LookVector.Z).Unit                    local flatRight = Vector3.new(camera.CFrame.RightVector.X, 0, camera.CFrame.RightVector.Z).Unit                                        -- Phân tích lực đẩy từ Joystick: Bao nhiêu phần là tiến/lùi, bao nhiêu là trái/phải                    local forwardInput = flatLook:Dot(moveDir)                    local rightInput = flatRight:Dot(moveDir)                                        -- Chuyển lực đẩy đó thành hướng bay 3D dựa trên góc ngước lên/xuống của Camera                    local flyDir = (camera.CFrame.LookVector * forwardInput) + (camera.CFrame.RightVector * rightInput)                                        -- Chuẩn hóa lại và áp dụng tốc độ                    if flyDir.Magnitude > 0 then                        bv.Velocity = flyDir.Unit * speed                    else                        bv.Velocity = Vector3.new(0, 0.1, 0)                    end                else                    bv.Velocity = Vector3.new(0, 0.1, 0) -- Đứng im lơ lửng khi thả tay                end                task.wait()            end            if bv then bv:Destroy() end            if bg then bg:Destroy() end            hum.PlatformStand = false        end)    else        FlyBtn.Text = "BẬT BAY"        FlyBtn.BackgroundColor3 = Color3.fromRGB(60, 60, 60)    endend)
